mapper.select:
/*UsimDlvryCanMapper.getUsimDlvryCanTransferTargetCnt*/
SELECT ETC1
FROM CMN_GRP_CD_MST
WHERE GRP_ID = 'DEV0003'
  AND USG_YN = 'Y'
  AND CD_VAL = #{cdVal}

/*UsimDlvryCanMapper.getUsimDlvryCanTransferList*/
SELECT V.SELF_DLVRY_IDX
      ,V.HIST_YN
      ,CASE WHEN V.CSTMR_NATIVE_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(V.CSTMR_NATIVE_RRN), 1, 7) || '******')
            ELSE NULL END AS CSTMR_NATIVE_RRN
FROM (
        /*계약번호가 추후 등록된 택배구매 케이스-개통정보가 이미 이관된 경우만 추출*/









        /*개통과 연관없는 택배구매 케이스*/
        SELECT A.SELF_DLVRY_IDX, 'N' AS HIST_YN, A.CSTMR_NATIVE_RRN
        FROM MCP_REQUEST_SELF_DLVRY@DL_MCP A
            ,MCP_REQUEST@DL_MCP B
        WHERE A.REQUEST_KEY = B.REQUEST_KEY(+)
          AND A.TRNS_YN IS NULL
          AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
          AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM)
          AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = B.CONTRACT_NUM)
        UNION ALL
        /*택배구매시도이력만 존재하는 케이스*/
        SELECT A.SELF_DLVRY_IDX, 'Y' AS HIST_YN, A.CSTMR_NATIVE_RRN
        FROM MCP_REQUEST_SELF_DLVRY_HIST@DL_MCP A
        WHERE A.TRNS_YN IS NULL
          AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
          AND NOT EXISTS (SELECT 1 FROM MCP_REQUEST_SELF_DLVRY@DL_MCP WHERE SELF_DLVRY_IDX = A.SELF_DLVRY_IDX)
      ) V
  WHERE ROWNUM <= #{targetCnt}

/*UsimDlvryCanMapper.getUsimDlvryNowCanTransferList*/
SELECT V.SELF_DLVRY_IDX
      ,V.HIST_YN
      ,CASE WHEN V.CSTMR_NATIVE_RRN IS NOT NULL THEN CRYPTO_AES256.ENC_AES(SUBSTR(CRYPTO_AES256.DEC_AES(V.CSTMR_NATIVE_RRN), 1, 7) || '******')
            ELSE NULL END AS CSTMR_NATIVE_RRN
FROM (
        /*계약번호가 추후 등록된 바로배송 케이스-개통정보가 이미 이관된 경우만 추출*/









      /*개통과 연관없는 바로배송 구매 케이스*/
      SELECT A.SELF_DLVRY_IDX, 'N' AS HIST_YN, A.CSTMR_NATIVE_RRN
      FROM MCP_REQUEST_NOW_DLVRY@DL_MCP A
          ,MCP_REQUEST@DL_MCP B
      WHERE A.REQUEST_KEY = B.REQUEST_KEY(+)
        AND A.TRNS_YN IS NULL
        AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
        AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM)
        AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO WHERE SRL_IF_ID = B.RES_NO)
      UNION ALL
      /*바로배송 구매시도이력만 존재하는 케이스*/
      SELECT A.SELF_DLVRY_IDX, 'Y' AS HIST_YN, A.CSTMR_NATIVE_RRN
      FROM MCP_REQUEST_NOW_DLVRY_HIST@DL_MCP A
      WHERE A.TRNS_YN IS NULL
        AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
        AND NOT EXISTS (SELECT 1 FROM MCP_REQUEST_NOW_DLVRY@DL_MCP WHERE SELF_DLVRY_IDX = A.SELF_DLVRY_IDX)
  ) V
  WHERE ROWNUM <= #{targetCnt}

/* UsimDlvryCanMapper.getUsimDlvryCanDeleteList */
SELECT V.SELF_DLVRY_IDX
      ,V.HIST_YN
FROM (
       /*개통해지와 연관없는 택배구매 케이스*/
       SELECT A.SELF_DLVRY_IDX, 'N' AS HIST_YN
       FROM MCP_REQUEST_SELF_DLVRY@DL_CAN A
           ,MSP_REQUEST@DL_CAN B
       WHERE A.REQUEST_KEY = B.REQUEST_KEY(+)
         AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
         AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO@DL_CAN WHERE CONTRACT_NUM = A.CONTRACT_NUM)
         AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO@DL_CAN WHERE SRL_IF_ID = B.RES_NO)
       UNION ALL
       /*택배구매시도이력만 존재하는 케이스*/
       SELECT A.SELF_DLVRY_IDX, 'Y' AS HIST_YN
       FROM MCP_REQUEST_SELF_DLVRY_HIST@DL_CAN A
       WHERE A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
       AND NOT EXISTS (SELECT 1 FROM MCP_REQUEST_SELF_DLVRY@DL_CAN WHERE SELF_DLVRY_IDX = A.SELF_DLVRY_IDX)
    ) V
WHERE ROWNUM <= #{targetCnt}

/*UsimDlvryCanMapper.getUsimDlvryNowCanDeleteList*/
SELECT V.SELF_DLVRY_IDX
      ,V.HIST_YN
FROM (
       /*개통해지와 연관없는 바로배송 구매 케이스*/
       SELECT A.SELF_DLVRY_IDX, 'N' AS HIST_YN
       FROM MCP_REQUEST_NOW_DLVRY@DL_CAN A
           ,MSP_REQUEST@DL_CAN B
       WHERE A.REQUEST_KEY = B.REQUEST_KEY(+)
         AND A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
         AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO@DL_CAN WHERE CONTRACT_NUM = A.CONTRACT_NUM)
         AND NOT EXISTS (SELECT 1 FROM MSP_JUO_SUB_INFO@DL_CAN WHERE SRL_IF_ID = B.RES_NO)
       UNION ALL
       /*바로배송 구매시도이력만 존재하는 케이스*/
       SELECT A.SELF_DLVRY_IDX, 'Y' AS HIST_YN
       FROM MCP_REQUEST_NOW_DLVRY_HIST@DL_CAN A
       WHERE A.SYS_RDATE < TRUNC(SYSDATE) - #{stdrDay}
       AND NOT EXISTS (SELECT 1 FROM MCP_REQUEST_NOW_DLVRY@DL_CAN WHERE SELF_DLVRY_IDX = A.SELF_DLVRY_IDX)
    ) V
WHERE ROWNUM <= #{targetCnt}
